export const MAP_COLS = 200;
export const MAP_ROWS = WORLD_MAP_ROWS.length;

// Pre-compute land grid as a flat boolean array for fast lookup
export const LAND_GRID: boolean[] = [];
for (let r = 0; r < MAP_ROWS; r++) {
  const row = WORLD_MAP_ROWS[r] || "";
  for (let c = 0; c < MAP_COLS; c++) {
    LAND_GRID[r * MAP_COLS + c] = row[c] === "1";
  }
}

// Pre-compute deterministic phases for land dots
export const PHASES: number[] = [];
for (let r = 0; r < MAP_ROWS; r++) {
  for (let c = 0; c < MAP_COLS; c++) {
    PHASES[r * MAP_COLS + c] = ((c * 7 + r * 13) % 23) / 23;
  }
}
